function getNextWeekday(date, targetDay) {
  const days = {
    'Lundi': 1, 'Mardi': 2, 'Mercredi': 3, 'Jeudi': 4, 
    'Vendredi': 5, 'Samedi': 6, 'Dimanche': 0
  };
  const targetDayNum = days[targetDay];
  if (targetDayNum === undefined) return date;
  const currentDay = date.getDay();
  let daysToAdd = targetDayNum - currentDay;
  if (daysToAdd <= 0) {
    daysToAdd += 7;
  }
  const newDate = new Date(date);
  newDate.setDate(newDate.getDate() + daysToAdd);
  return newDate;
}

// Fonction pour ajouter des jours ouvrés (lundi à vendredi)
function addWorkingDays(startDate, workingDaysToAdd) {
  const result = new Date(startDate);
  let daysAdded = 0;

  while (daysAdded < workingDaysToAdd) {
    result.setDate(result.getDate() + 1);
    const dayOfWeek = result.getDay();

    // Si c'est un jour ouvré (lundi=1 à vendredi=5)
    if (dayOfWeek >= 1 && dayOfWeek <= 5) {
      daysAdded++;
    }
  }

  return result;
}

// Traitement de chaque tâche
const processedItems = [];

for (const item of $input.all()) {
  // Extraire la date depuis l'objet Start
  const startDateString = item.json.Start.start;
  const startDate = new Date(startDateString);

  const repeatDays = item.json['Répéter Nb'];
  const preferredDay = item.json['Jours semaine'];

  // Calculer la nouvelle date (Start + Répéter Nb)
  const newStartDate = new Date(startDate);
  newStartDate.setDate(newStartDate.getDate() + repeatDays);

  // Ajuster selon le jour préféré si défini
  let finalDate = newStartDate;
  if (preferredDay && preferredDay !== '') {
    finalDate = getNextWeekday(newStartDate, preferredDay);
  }

  // Calculer la deadline = Start + "Dead line + Nb" en jours ouvrés
  let deadline = null;
  if (item.json['Dead line + Nb']) {
    const deadlineDate = addWorkingDays(startDate, item.json['Dead line + Nb']);
    // CORRECTION : Format objet pour Notion
    deadline = { start: deadlineDate.toISOString().split('T')[0] };
  }

  // Préparer les données pour la création et la mise à jour
  processedItems.push({
    // Données pour créer la tâche dans Master Tâches
    taskData: {
      name: item.json.Name,
      type_id: item.json['Type de tache ID'],
      responsable_id: item.json['Responsable ID'],
      equipe_id: item.json['Équipe'],
      priorite: item.json['Priorité'],
      deadline: deadline,
      status: 'À faire',
      note: item.json.Note
    },
    // Données pour mettre à jour la tâche récurrente
    updateData: {
      id: item.json.id,
      // CORRECTION : Format objet pour Notion
      newStartDate: { start: finalDate.toISOString().split('T')[0] }
    }
  });
}

return processedItems.map(item => ({ json: item }));

